// Robust parser for batch arrays
const allInputs = $input.all();
const sourceItems = $('Prepare Batch for LLM').first().json.items;
const results = [];

for (let i = 0; i < allInputs.length; i++) {
  const inputData = allInputs[i].json || {};
  let jsonText = '';

  try {
    // Extract text
    if (inputData.content && Array.isArray(inputData.content)) {
      jsonText = inputData.content[0]?.text || '';
    } else {
      jsonText = inputData.text || inputData.content || '';
    }

    // Remove markdown blocks
    jsonText = jsonText
      .replace(/^```json\s*/i, '')
      .replace(/^```\s*/, '')
      .replace(/\s*```$/, '')
      .trim();

    // Extract array if wrapped
    const arrayMatch = jsonText.match(/\[\s*\{[\s\S]*\]/);
    if (arrayMatch) {
      jsonText = arrayMatch[0];
    }

    // Parse the array
    const parsedArray = JSON.parse(jsonText);

    // Validate it's an array
    if (!Array.isArray(parsedArray)) {
      throw new Error('Output is not an array');
    }

    // Add item_id to each object and add to results
    parsedArray.forEach((item, idx) => {
      const sourceData = sourceItems[idx];
      results.push({
        json: {
          ...item,
          item_id: sourceData.item_id
        }
      });
    });

  } catch (error) {
    // Failed - return error
    results.push({
      json: {
        error: 'JSON PARSING FAILED',
        error_message: error.message,
        raw_preview: jsonText.substring(0, 500),
        item_id: sourceItems[0]?.item_id || 'unknown'
      }
    });
  }
}

return results;

// Split items into batches of 5 and include topic
const items = $input.all();
const topic = $('Read System State').item.json.topic;  // ← Get topic
const BATCH_SIZE = 5;
const batches = [];

for (let i = 0; i < items.length; i += BATCH_SIZE) {
  batches.push({
    json: {
      batch_number: Math.floor(i / BATCH_SIZE) + 1,
      total_batches: Math.ceil(items.length / BATCH_SIZE),
      topic: topic,  // ← Include topic in each batch
      items: items.slice(i, i + BATCH_SIZE).map(item => item.json),
      is_last_batch: i + BATCH_SIZE >= items.length
    }
  });
}

return batches;

// Extract current batch and format for LLM
const currentBatch = $input.first().json;

// Format each item for the LLM prompt
const formattedItems = currentBatch.items.map(item => ({
  item_id: item.item_id,
  title: item.title,
  url: item.url,
  content: item.raw_content
}));

return [{
  json: {
    topic: currentBatch.topic,  // ← Topic comes from Create Batches
    batch_info: {
      batch_number: currentBatch.batch_number,
      total_batches: currentBatch.total_batches,
      is_last_batch: currentBatch.is_last_batch
    },
    items: formattedItems
  }
}];

const topic = $('Read System State').first().json.topic;
const periodData = $('Read System State').first().json;

// Try to get counts from enrichment nodes
let itemsEnriched = 0;
let batchesProcessed = 0;

try {
  // Reference nodes before the loop - just count all items
  const selectItemsNode = $('Select Items to Enrich').all();
  itemsEnriched = selectItemsNode.length;

  const createBatchesNode = $('Create Batches').all();
  batchesProcessed = createBatchesNode.length;
} catch (error) {
  // Nodes didn't execute (FALSE branch), counts remain 0
  itemsEnriched = 0;
  batchesProcessed = 0;
}

return [{
  json: {
    topic: topic,
    workflow_id: 2,
    event: 'enrichment_complete',
    status: 'success',
    details: {
      period_start: periodData.period_start,
      period_end: periodData.period_end,
      items_enriched: itemsEnriched,
      batches_processed: batchesProcessed
    }
  }
}];

